1	//! Record-cell rendering (BEHAVIOR.md §3a, §3f): turning facts / rule instances
2	//! into the exact text that goes inside a record cell, including the observed
3	//! escaping, the fact-vs-function spacing, and the `\l`/`&nbsp;` line-wrapping
4	//! FORMAT.
5	//!
6	//! What is byte-exact here (verified against the corpus):
7	//!   * **Escaping** of record-label metacharacters `< > { } |`.
8	//!   * **Fact spacing** `Name( a, b )` (a space after `(` and before `)`) versus
9	//!     **function spacing** `f(a, b)` (no inner spaces) — mined over the corpus;
10	//!     a fact / relation symbol pads, an ordinary function application does not.
11	//!   * **Info-cell** shape `#<temporal> : <RuleName>` optionally followed by
12	//!     `[<action>, …]`.
13	//!   * The **wrap alignment**: a broken group's continuation lines are indented
14	//!     with `&nbsp;` runs to the column of the group's first element — i.e. just
15	//!     after `( ` for a fact, after `<` for a tuple, after `[` for an action list
16	//!     (verified across 188 192 wrapped cells: the indent always equals that
17	//!     first-element column). Physical segments are separated by `\l`.
18	//!
19	//! The wrap DECISION and the delimiter peel are byte-implemented by [`wrap_cell`],
20	//! pinned by a controlled live width sweep (BEHAVIOR.md §3f, QUERIES.log round 5):
21	//! a fact is laid out from its own column 0 with line width [`FILL_WIDTH`] = 87.
22	//! Two combinators, each byte-verified against captured probes:
23	//!   * a fact's **argument list** and a **tuple**'s elements use a greedy fill
24	//!     (`fillSep`): pack elements left-to-right, the `, ` separator trails the
25	//!     element it follows, and the next element wraps when it would pass column 87.
26	//!   * an info cell's **action list** uses a vertical `sep` (one action per line
27	//!     when the cell overflows).
28	//!
29	//! The **delimiter peel** at the fill-width boundary (byte-verified over the E-/W-
30	//! sweep fixtures): a tuple's `>` stays with the last element iff it fits, else it
31	//! peels onto its own line at the tuple's `<` column; a fact's `)` **always** peels
32	//! onto its own line at column 0 once the fact wraps (the padded ` )` space becomes
33	//! the break). An action list's `]` stays attached to the last action. The
34	//! continuation-line indent equals the broken group's first-element column
35	//! (`&nbsp;` runs). The one-element-lookahead observed earlier is subsumed: the
36	//! continuation packs greedily to the same width as the first line.
37	//!
38	//! Residual (characterised, not byte-implemented): [`wrap_cell`] triggers a wrap on
39	//! the cell's own flat width alone (correct for cells early on their record line).
40	//! When earlier cells push the absolute column high, tamarin's Wadler `group`/
41	//! `fits` decision wraps a cell **earlier** (its flat width alone can be well under
42	//! 87 — e.g. a 21-char fact deep in a wide record still peels its `)`), because
43	//! `fits` measures the flat rendering *plus the rest of the record line* against
44	//! the remaining width. Reproducing that needs the exact document tree; see
45	//! BEHAVIOR.md §3f.
46	
47	use crate::term::Term;
48	
49	/// Absolute per-fact line width of the record-cell pretty-printer, in columns,
50	/// measured from the functor at column 0. A fact whose flat rendering is `≤ 87`
51	/// columns is emitted on a single line; a wider one is broken (BEHAVIOR.md §3f).
52	/// Pinned by a live one-column width sweep that was invariant across functor
53	/// lengths (the boundary was always flat-width 87 fits / 88 breaks).
54	pub const FILL_WIDTH: usize = 87;
55	
56	/// The per-cell minimum wrap budget (BEHAVIOR.md §3f). Inside a record group the
57	/// cells share the [`FILL_WIDTH`] budget, but a cell's budget never drops below
58	/// this floor — a cell whose flat rendering is at most `MIN_CELL_BUDGET` columns
59	/// never wraps, however wide its siblings are. Pinned by a live probe: a sibling
60	/// forced far past the budget leaves the target fitting at flat ≤ 20, wrapping at
61	/// flat 21.
62	pub const MIN_CELL_BUDGET: usize = 20;
63	
64	/// The wrap budget of one cell in a record group (BEHAVIOR.md §3f). `flats` are the
65	/// flat visual widths of **every** cell in the same group (premises together, or
66	/// conclusions together — the info cell is its own single-cell group); `i` is the
67	/// target cell. The group shares [`FILL_WIDTH`]: the budget is what remains after
68	/// the *other* cells' flat widths, floored at [`MIN_CELL_BUDGET`]. The cell wraps
69	/// iff its own flat width exceeds this budget — equivalently, iff the group total
70	/// exceeds [`FILL_WIDTH`] and the cell's flat exceeds [`MIN_CELL_BUDGET`].
71	pub fn cell_budget(flats: &[usize], i: usize) -> usize {
72	    let others: usize = flats.iter().enumerate().filter(|(k, _)| *k != i).map(|(_, w)| *w).sum();
73	    FILL_WIDTH.saturating_sub(others).max(MIN_CELL_BUDGET)
74	}
75	
76	/// The wrap DECISION for a lone cell: a fact stays on a single record-cell line
77	/// iff its flat (un-wrapped) rendering is at most [`FILL_WIDTH`] columns wide.
78	/// `flat` is the fact's flat rendering (e.g. from [`Fact::render_flat`]); width is
79	/// counted in Unicode scalars, matching the observed column count. Verified
80	/// byte-exact at the boundary: an 87-column fact is single-line, an 88-column one
81	/// wraps (live probe, functor-length-invariant). For a cell sharing its group with
82	/// siblings use [`cell_budget`] to obtain the reduced budget.
83	pub fn fits_one_line(flat: &str) -> bool {
84	    flat.chars().count() <= FILL_WIDTH
85	}
86	
87	/// Number of top-level action facts in an info cell's action list `#t : Rule[…]`
88	/// (0 if there is no `[…]`). Counts the `, ` separators at bracket depth 0 inside
89	/// the `[ … ]`, honoring `()`/`<>`/`[]` nesting and `'…'` quotes. Used to apply the
90	/// observed rule (BEHAVIOR.md §3f): an info cell with **≥ 2** actions always renders
91	/// its list vertically (one action per line), independent of width.
92	pub fn count_info_actions(flat: &str) -> usize {
93	    let chars: Vec<char> = flat.chars().collect();
94	    let Some(open) = chars.iter().position(|&c| c == '[') else { return 0 };
95	    if chars.get(open + 1) == Some(&']') {
96	        return 0;
97	    }
98	    let mut depth = 0i32;
99	    let mut in_quote = false;
100	    let mut actions = 1usize;
101	    let mut i = open + 1;
102	    while i < chars.len() {
103	        let c = chars[i];
104	        if in_quote {
105	            if c == '\'' {
106	                in_quote = false;
107	            }
108	            i += 1;
109	            continue;
110	        }
111	        match c {
112	            '\'' => in_quote = true,
113	            '(' | '<' | '[' => depth += 1,
114	            ']' if depth == 0 => break,
115	            ')' | '>' | ']' => depth -= 1,
116	            ',' if depth == 0 && chars.get(i + 1) == Some(&' ') => actions += 1,
117	            _ => {}
118	        }
119	        i += 1;
120	    }
121	    actions
122	}
123	
124	/// Escape the metacharacters that are special inside a graphviz record label:
125	/// `< > { } |` each get a leading backslash. Everything else (including single
126	/// quotes, `~ $ ^ * ⊕`, spaces) is literal. Observed in every record cell.
127	pub fn escape_record(s: &str) -> String {
128	    let mut out = String::with_capacity(s.len());
129	    for c in s.chars() {
130	        match c {
131	            '<' | '>' | '{' | '}' | '|' => {
132	                out.push('\\');
133	                out.push(c);
134	            }
135	            _ => out.push(c),
136	        }
137	    }
138	    out
139	}
140	
141	/// A fact / relation atom occupying one premise or conclusion cell, e.g.
142	/// `!SessionKey( <…>, $A, H1 )`. `name` is the fact symbol (may start with `!`
143	/// for a persistent fact); `args` are its term arguments.
144	#[derive(Clone, Debug)]
145	pub struct Fact {
146	    pub name: String,
147	    pub args: Vec<Term>,
148	}
149	
150	impl Fact {
151	    pub fn new(name: &str, args: Vec<Term>) -> Self {
152	        Fact { name: name.to_string(), args }
153	    }
154	
155	    /// Flat (un-wrapped, un-escaped) surface rendering with **fact spacing**:
156	    /// `Name( a, b )`, and `Name( )` when it has no arguments. Argument terms use
157	    /// the ordinary term rendering (functions `f(a, b)` without inner spaces,
158	    /// tuples `<a, b>`). This matches every un-wrapped fact cell in the corpus.
159	    pub fn render_flat(&self) -> String {
160	        let inner: Vec<String> = self.args.iter().map(Term::render_full).collect();
161	        pad(&self.name, &inner)
162	    }
163	
164	    /// Flat rendering with abbreviations applied to registered sub-terms
165	    /// (`table` maps a term's full rendering to its abbreviation name).
166	    pub fn render_flat_abbrev(&self, table: &std::collections::HashMap<String, String>) -> String {
167	        let inner: Vec<String> = self.args.iter().map(|t| t.render_abbrev(table)).collect();
168	        pad(&self.name, &inner)
169	    }
170	}
171	
172	/// Fact spacing `Name( a, b )`, collapsing to `Name( )` for zero arguments
173	/// (observed: `NoA( )`, `!Semistate_1( )` — a single space between the parens).
174	fn pad(name: &str, args: &[String]) -> String {
175	    if args.is_empty() {
176	        format!("{}( )", name)
177	    } else {
178	        format!("{}( {} )", name, args.join(", "))
179	    }
180	}
181	
182	/// The info cell of a rule instance: `#<temporal> : <rule>` plus, when the rule
183	/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
184	/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
185	pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
186	    if actions.is_empty() {
187	        format!("#{} : {}", temporal, rule)
188	    } else {
189	        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
190	        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
191	    }
192	}
193	
194	/// Lay `items` out as a **fill** to a target `width`, starting at column
195	/// `open_col` (the alignment column of the group's first element). Returns the
196	/// physical lines *without* the `&nbsp;` indent — [`join_wrapped`] adds it.
197	///
198	/// Greedy fill: keep appending `sep`-joined items to the current line while it
199	/// fits in `width`; otherwise start a new line. This reproduces the observed
200	/// packing (several short arguments share a line, then a break) **given** the
201	/// width; the width itself is the documented gap.
202	pub fn fill(items: &[String], sep: &str, open_col: usize, width: usize) -> Vec<String> {
203	    if items.is_empty() {
204	        return vec![String::new()];
205	    }
206	    let mut lines: Vec<String> = Vec::new();
207	    let mut cur = String::new();
208	    let mut col = open_col;
209	    for (i, it) in items.iter().enumerate() {
210	        let piece = if cur.is_empty() {
211	            it.clone()
212	        } else {
213	            format!("{}{}", sep, it)
214	        };
215	        if !cur.is_empty() && col + piece.chars().count() > width {
216	            lines.push(std::mem::take(&mut cur));
217	            col = open_col;
218	            cur.push_str(it);
219	            col += it.chars().count();
220	        } else {
221	            cur.push_str(&piece);
222	            col += piece.chars().count();
223	        }
224	        let _ = i;
225	    }
226	    lines.push(cur);
227	    lines
228	}
229	
230	/// Greedy paragraph fill at the **known** width [`FILL_WIDTH`], reproducing the
231	/// observed record-cell packing: elements are laid left-to-right starting at
232	/// column `open_col`; the separator `sep` (e.g. `", "`) is emitted after each
233	/// element and **stays on the current line**, and the next element starts a new
234	/// line iff it would push past [`FILL_WIDTH`] from that point. This reproduces the
235	/// observed first-line packing exactly (e.g. an `Out( <'a01', … > )` whose tuple
236	/// overflows keeps eleven `'aNN'` elements plus the trailing `", "` on line 0,
237	/// then breaks). Continuation lines carry the [`FILL_WIDTH`]-wide `&nbsp;` indent
238	/// via [`join_wrapped`].
239	///
240	/// KNOWN RESIDUAL (BEHAVIOR.md §3f): tamarin's underlying `fsep`-style combinator
241	/// has a one-element lookahead that lets a *continuation* line hold one more
242	/// element than the first line at the same start column; this greedy pass packs
243	/// the first line exactly but a continuation line one element short of that
244	/// lookahead, and it does not model the closing-delimiter peel (`>`/`)` onto their
245	/// own aligned lines) that appears when the last element fills the line.
246	pub fn paragraph_fill(items: &[String], sep: &str, open_col: usize) -> Vec<String> {
247	    if items.is_empty() {
248	        return vec![String::new()];
249	    }
250	    let sep_w = sep.chars().count();
251	    let mut lines: Vec<String> = Vec::new();
252	    let mut cur = String::new();
253	    let mut col = open_col;
254	    for (i, it) in items.iter().enumerate() {
255	        let w = it.chars().count();
256	        if i == 0 {
257	            cur.push_str(it);
258	            col += w;
259	        } else if col + w <= FILL_WIDTH {
260	            cur.push_str(it);
261	            col += w;
262	        } else {
263	            lines.push(std::mem::take(&mut cur));
264	            col = open_col;
265	            cur.push_str(it);
266	            col += w;
267	        }
268	        if i + 1 < items.len() {
269	            // The separator trails the element it follows and stays on the line;
270	            // the *next* element's fit is tested from past it.
271	            cur.push_str(sep);
272	            col += sep_w;
273	        }
274	    }
275	    lines.push(cur);
276	    lines
277	}
278	
279	/// Join physical `lines` (a FILL of same-aligned elements, e.g. a broken action
280	/// list `[a1, a2]`) into a single record-cell string using the observed wrap
281	/// format: each physical line is followed by `\l`, and every continuation line is
282	/// prefixed by `open_col` `&nbsp;` entities (the verified alignment indent). The
283	/// trailing `\l` after the last line is part of the observed format (graphviz
284	/// left-justification). The caller escapes the line contents first (via
285	/// [`escape_record`]) — `\l` and `&nbsp;` are literal control sequences and must
286	/// not be escaped.
287	///
288	/// This reproduces the fill case where the closing delimiter stays attached to
289	/// the last element (`… )]`). A function/fact whose closing `)` breaks onto its
290	/// *own* line at the functor column is a distinct layout the pretty-printer's
291	/// break decision produces (a documented GAP), not modelled here.
292	pub fn join_wrapped(lines: &[String], open_col: usize) -> String {
293	    let indent = "&nbsp;".repeat(open_col);
294	    let mut out = String::new();
295	    for (i, ln) in lines.iter().enumerate() {
296	        if i > 0 {
297	            out.push_str(&indent);
298	        }
299	        out.push_str(ln);
300	        out.push_str("\\l");
301	    }
302	    out
303	}
304	
305	/// Width of a rendered fragment in the pretty-printer's column model: Unicode
306	/// scalar count (matches the observed column boundary).
307	fn width(s: &str) -> usize {
308	    s.chars().count()
309	}
310	
311	/// One physical line of a wrapped cell: its `&nbsp;` indent column and its
312	/// un-escaped text (escaping is applied when the lines are joined).
313	type PLine = (usize, String);
314	
315	/// One fill element with the separator that precedes it, the indent to use if it
316	/// starts a new line, and whether a break before it is forced (`hard`).
317	struct Unit {
318	    sep: &'static str,
319	    text: String,
320	    indent: usize,
321	    hard: bool,
322	}
323	
324	/// Greedy fill layout (BEHAVIOR.md §3f). Starting from `open_text` at column
325	/// `start_col`, place each unit's separator on the current line and then its text,
326	/// wrapping to the unit's indent when the text would pass the cell's `budget` (or
327	/// on a `hard` unit). Returns the physical lines. `budget` is the cell's shared
328	/// group budget ([`cell_budget`]); for a lone cell it is [`FILL_WIDTH`].
329	///
330	/// `drop_break_space`: at a break, a single trailing space of the just-finished
331	/// line is dropped. A **fact argument** list breaks after the bare `,` (observed
332	/// `Init_1( a, b,\l…`), so it passes `true`; a **tuple element** list keeps the
333	/// `, ` before the break (observed `<…, x8.4, \l…`), so it passes `false`.
334	fn run_layout(open_text: &str, start_col: usize, units: &[Unit], budget: usize, drop_break_space: bool) -> Vec<PLine> {
335	    let mut lines: Vec<PLine> = Vec::new();
336	    let mut cur = open_text.to_string();
337	    let mut col = start_col;
338	    let mut line_indent = 0usize;
339	    for u in units {
340	        cur.push_str(u.sep);
341	        col += width(u.sep);
342	        let w = width(&u.text);
343	        if u.hard || col + w > budget {
344	            if drop_break_space && cur.ends_with(' ') {
345	                cur.pop();
346	            }
347	            lines.push((line_indent, std::mem::take(&mut cur)));
348	            line_indent = u.indent;
349	            cur.push_str(&u.text);
350	            col = u.indent + w;
351	        } else {
352	            cur.push_str(&u.text);
353	            col += w;
354	        }
355	    }
356	    lines.push((line_indent, cur));
357	    lines
358	}
359	
360	/// Split `s` at top-level occurrences of `", "` — respecting `()`/`<>`/`[]` nesting
361	/// and `'…'` quotes — into the comma-separated elements of a fill group.
362	fn split_top_commas(s: &str) -> Vec<String> {
363	    let chars: Vec<char> = s.chars().collect();
364	    let mut parts: Vec<String> = Vec::new();
365	    let mut cur = String::new();
366	    let mut depth = 0i32;
367	    let mut in_quote = false;
368	    let mut i = 0;
369	    while i < chars.len() {
370	        let c = chars[i];
371	        if in_quote {
372	            cur.push(c);
373	            if c == '\'' {
374	                in_quote = false;
375	            }
376	            i += 1;
377	            continue;
378	        }
379	        match c {
380	            '\'' => {
381	                in_quote = true;
382	                cur.push(c);
383	                i += 1;
384	            }
385	            '(' | '<' | '[' => {
386	                depth += 1;
387	                cur.push(c);
388	                i += 1;
389	            }
390	            ')' | '>' | ']' => {
391	                depth -= 1;
392	                cur.push(c);
393	                i += 1;
394	            }
395	            ',' if depth == 0 && i + 1 < chars.len() && chars[i + 1] == ' ' => {
396	                parts.push(std::mem::take(&mut cur));
397	                i += 2;
398	            }
399	            _ => {
400	                cur.push(c);
401	                i += 1;
402	            }
403	        }
404	    }
405	    parts.push(cur);
406	    parts
407	}
408	
409	fn is_tuple(s: &str) -> bool {
410	    s.starts_with('<') && s.ends_with('>')
411	}
412	
413	/// Lay out a tuple `<e1, e2, …>` whose `<` sits at column `base_col`: fill the
414	/// elements (`fillSep`) at `base_col + 1`, and peel the `>` to its own line at
415	/// `base_col` iff it does not fit on the last element's line. `budget` is the
416	/// enclosing cell's group budget ([`cell_budget`]).
417	fn layout_tuple(inner: &str, base_col: usize, budget: usize) -> Vec<PLine> {
418	    let elems = split_top_commas(inner);
419	    let open_col = base_col + 1;
420	    let mut units: Vec<Unit> = Vec::with_capacity(elems.len() + 1);
421	    for (i, e) in elems.iter().enumerate() {
422	        units.push(Unit { sep: if i == 0 { "" } else { ", " }, text: e.clone(), indent: open_col, hard: false });
423	    }
424	    units.push(Unit { sep: "", text: ">".to_string(), indent: base_col, hard: false });
425	    run_layout("<", open_col, &units, budget, false)
426	}
427	
428	/// Lay out a fact / relation cell `NAME( a1, a2, … )`. If its flat rendering fits
429	/// the cell's `budget` it stays on one line. Otherwise its arguments fill at the
430	/// argument column; a sole tuple argument recurses into [`layout_tuple`]; and the
431	/// closing `)` peels onto its own line at column 0 (the padded ` )` space becomes
432	/// the break). `budget` is the cell's group budget ([`cell_budget`]); for a lone
433	/// cell it is [`FILL_WIDTH`].
434	fn layout_fact(flat: &str, budget: usize) -> Vec<PLine> {
435	    if width(flat) <= budget {
436	        return vec![(0, flat.to_string())];
437	    }
438	    let Some(lp) = flat.find("( ") else {
439	        return vec![(0, flat.to_string())];
440	    };
441	    if !flat.ends_with(" )") {
442	        return vec![(0, flat.to_string())];
443	    }
444	    let open_str = &flat[..lp + 2]; // "NAME( "
445	    let content = &flat[lp + 2..flat.len() - 2];
446	    let open_col = width(open_str);
447	    let args = split_top_commas(content);
448	
449	    // A sole tuple argument: the fact opens "NAME( <" and the tuple fills inside.
450	    if args.len() == 1 && is_tuple(&args[0]) {
451	        let inner = &args[0][1..args[0].len() - 1];
452	        let tlines = layout_tuple(inner, open_col, budget);
453	        let mut lines: Vec<PLine> = Vec::with_capacity(tlines.len() + 2);
454	        lines.push((0, format!("{}{}", open_str, tlines[0].1)));
455	        for t in &tlines[1..] {
456	            lines.push(t.clone());
457	        }
458	        lines.push((0, ")".to_string()));
459	        return lines;
460	    }
461	
462	    // General fill of the (atomic) arguments; the fact's `)` always peels to col 0.
463	    let mut units: Vec<Unit> = Vec::with_capacity(args.len() + 1);
464	    for (i, a) in args.iter().enumerate() {
465	        units.push(Unit { sep: if i == 0 { "" } else { ", " }, text: a.clone(), indent: open_col, hard: false });
466	    }
467	    units.push(Unit { sep: "", text: ")".to_string(), indent: 0, hard: true });
468	    run_layout(open_str, open_col, &units, budget, true)
469	}
470	
471	/// Lay out an info cell `#t : Rule[a1, a2, …]`. The action list uses a vertical
472	/// `sep` — one action per line — and goes vertical **whenever the list has ≥ 2
473	/// actions** (independent of width) OR the cell overflows its `budget` (a lone
474	/// action that is too wide). The trailing `,` is kept on each non-final line and
475	/// the `]` is attached to the last action (BEHAVIOR.md §3f). `budget` is the info
476	/// cell's own budget ([`FILL_WIDTH`], since the info cell is alone in its group).
477	fn layout_info(flat: &str, budget: usize) -> Vec<PLine> {
478	    let Some(lb) = flat.find('[') else {
479	        return vec![(0, flat.to_string())];
480	    };
481	    if !flat.ends_with(']') {
482	        return vec![(0, flat.to_string())];
483	    }
484	    let open_str = &flat[..lb + 1]; // "#t : Rule["
485	    let content = &flat[lb + 1..flat.len() - 1];
486	    let open_col = width(open_str);
487	    let acts = split_top_commas(content);
488	    // Stay on one line only when there is at most one action AND it fits the budget;
489	    // an action list of ≥ 2 always breaks vertically.
490	    if acts.len() <= 1 && width(flat) <= budget {
491	        return vec![(0, flat.to_string())];
492	    }
493	    let mut units: Vec<Unit> = Vec::with_capacity(acts.len());
494	    for (i, a) in acts.iter().enumerate() {
495	        // Each action begins its own line (a vertical `sep`, hard break after the
496	        // first); non-final actions carry a trailing `,`, the last carries `]`.
497	        let text = if i + 1 < acts.len() { format!("{},", a) } else { format!("{}]", a) };
498	        units.push(Unit { sep: "", text, indent: open_col, hard: i > 0 });
499	    }
500	    run_layout(open_str, open_col, &units, budget, false)
501	}
