356	/// Build the DOT [`Graph`] for a [`System`]: allocate ids in emission order (so id
357	/// order == file order), emit free (non-clustered) node statements at the top
358	/// level, then the `cluster_…` subgraph blocks (role records, grouped by cluster
359	/// label in first-appearance order), then edges, then the legend sink-block + its
360	/// invis edges. Header is inferred from roles (§4).
361	pub fn generate(sys: &System) -> Graph {
362	    let mut alloc = NodeIdAllocator::new();
363	    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
364	
365	    // Free top-level node statements, in emission order.
366	    let mut free: Vec<Stmt> = Vec::new();
367	    // Clusters: label -> (color, record statements), with first-appearance order.
368	    let mut cluster_order: Vec<String> = Vec::new();
369	    let mut clusters: std::collections::HashMap<String, (String, Vec<Stmt>)> =
370	        std::collections::HashMap::new();
371	
372	    // Pass 1: allocate ids and build node statements in emission order. A clustered
373	    // record's statement is routed into its cluster bucket; everything else is free.
374	    for node in &sys.nodes {
375	        if let Some(spec) = node.record_spec() {
376	            let ids = alloc.record(spec.cell_count());
377	            let mut it = ids.ports.into_iter();
378	            let ports_prem: Vec<String> = (0..spec.premises.len()).map(|_| it.next().unwrap()).collect();
379	            let port_info = it.next().unwrap();
380	            let ports_concl: Vec<String> =
381	                (0..spec.conclusions.len()).map(|_| it.next().unwrap()).collect();
382	            let rec = build_record(&spec, &ports_prem, &port_info, &ports_concl);
383	            let stmt = Stmt::Node(Node::record(ids.node.clone(), rec));
384	            match &spec.cluster {
385	                Some(c) => {
386	                    let entry = clusters.entry(c.label.clone()).or_insert_with(|| {
387	                        cluster_order.push(c.label.clone());
388	                        (c.color.clone(), Vec::new())
389	                    });
390	                    entry.1.push(stmt);
391	                }
392	                None => free.push(stmt),
393	            }
394	            resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
395	            continue;
396	        }
397	        let id = alloc.node();
398	        let stmt = match node {
399	            GraphNode::Knowledge { term, temporal } => {
400	                let label = format!("!KU( {} ) @ #{}", term, temporal);
401	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray")))
402	            }
403	            GraphNode::Action { fact, temporal } => {
404	                let label = format!("{} @ #{}", fact, temporal);
405	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue")))
406	            }
407	            GraphNode::Compressed { temporal, rule } => {
408	                let label = format!("#{} : {}", temporal, rule);
409	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label)))
410	            }
411	            GraphNode::Temporal { var } => {
412	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(format!("#{}", var))))
413	            }
414	            GraphNode::OpenTarget { node_var, premise_index } => {
415	                Stmt::Node(Node::shaped(id.clone(), Shaped::invtrapezium(node_var, *premise_index)))
416	            }
417	            GraphNode::Shaped { label, shape, color } => Stmt::Node(Node::shaped(
418	                id.clone(),
419	                Shaped { label: label.clone(), shape: shape.clone(), color: color.clone() },
420	            )),
421	            GraphNode::Rule(_) | GraphNode::RawRule(_) => unreachable!("records handled above"),
422	        };
423	        free.push(stmt);
424	        resolved.push(Resolved::Node(id));
425	    }
426	
427	    // Assemble: free nodes, then clusters (first-appearance order), then edges.
428	    let mut g = Graph::new(Header::Simple);
429	    for s in free {
430	        g.push(s);
431	    }
432	    for label in &cluster_order {
433	        let (color, body) = clusters.remove(label).unwrap();
434	        g.push(Stmt::Cluster(Cluster { label: label.clone(), color, body }));
435	    }
436	
437	    // Pass 2: edges.
438	    for e in &sys.edges {
439	        let src = endpoint(&resolved, e.src);
440	        let dst = endpoint(&resolved, e.dst);
441	        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
442	    }
443	
444	    // Pass 3: legend sink-block, then its invis edges (observed order).
445	    if let Some(html) = &sys.legend_html {
446	        if !html.is_empty() {
447	            let legend_id = alloc.node();
448	            let block = RankBlock {
449	                rank: "sink".into(),
450	                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
451	            };
452	            g.push(Stmt::RankBlock(block));
453	            for (from, ()) in &sys.legend_edges {
454	                let src = endpoint(&resolved, *from);
455	                g.push(Stmt::Edge(Edge {
456	                    src,
457	                    dst: EndPoint::node(legend_id.clone()),
458	                    attrs: EdgeStyle::Invis.attrs(),
459	                }));
460	            }
461	        }
462	    }
463	
464	    g.set_inferred_header();
465	    g
466	}
