468	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
469	/// Empty premise / conclusion groups are dropped; the info group is always kept
470	/// (matches the observed group structure). Each group's cells share the record
471	/// wrap budget: within a premise or conclusion group a cell wraps when its flat
472	/// width exceeds `max(87 − Σ other cell flats, 20)` (BEHAVIOR.md §3f); the info
473	/// cell is its own single-cell group (budget 87). Cell text is wrapped and escaped
474	/// by [`wrap_cell_budget`].
475	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
476	    let mut columns: Vec<Vec<Cell>> = Vec::new();
477	    if !spec.premises.is_empty() {
478	        columns.push(group_cells(&spec.premises, ports_prem));
479	    }
480	    // The info cell is its own single-cell group (full width), fed through the
481	    // faithful layout engine at [`FILL_WIDTH`].
482	    columns.push(vec![Cell::new(port_info, wrap_cell_dot(&spec.info, FILL_WIDTH as isize))]);
483	    if !spec.conclusions.is_empty() {
484	        columns.push(group_cells(&spec.conclusions, ports_concl));
485	    }
486	    Record {
487	        columns,
488	        fillcolor: spec.fillcolor.clone(),
489	        fontcolor: spec.fontcolor.clone(),
490	        role: Role(spec.role.clone()),
491	    }
492	}
