494	/// The per-cell line widths of one record group (all premises together, or all
495	/// conclusions together): the cells share the group's [`FILL_WIDTH`] budget
496	/// (BEHAVIOR.md §3f), and each cell is then laid out INDEPENDENTLY at its width by
497	/// the faithful pretty-printer ([`crate::doclayout`]).
498	///
499	/// A single width per cell (the exact engine turns it into the wrap decision AND
500	/// the fill packing — no separate trigger/fill split is needed once the fitting is
501	/// faithful). The width comes from a **smallest-flat-first** allocation that
502	/// reproduces the greedy pretty-printer's coupling: process cells in increasing
503	/// flat width; each cell's width is `max(87 − Σ others' occupancy, 20)`, where an
504	/// already-processed sibling occupies `min(flat, its own width)` (a wrapping
505	/// sibling takes only the width it was allocated) and an un-processed (wider)
506	/// sibling still occupies its full flat width. So the narrow cells pack tight
507	/// first and the widest cell expands into the room their allocations leave — e.g.
508	/// the Wide-rule conclusion group `[Ack 25, Big 68, Out 11]`: `Out` fits (11 ≤ 20
509	/// floor); `Ack`, seen while `Big` is still at flat 68, is squeezed to 20 and
510	/// wraps; `Big`, placed last, sees `Ack`'s occupancy 20 and gets `87 − 20 − 11 =
511	/// 56` → eight tuple elements on its first line, `Out` stays flat. The `20` floor
512	/// is the observed per-cell minimum (a cell of flat ≤ 20 never wraps).
513	pub fn group_widths(widths: &[usize]) -> Vec<usize> {
514	    let n = widths.len();
515	    let mut order: Vec<usize> = (0..n).collect();
516	    order.sort_by_key(|&i| widths[i]); // stable: ties keep group order
517	    let mut occ = widths.to_vec();
518	    let mut out = vec![0usize; n];
519	    let full = FILL_WIDTH as usize;
520	    for &i in &order {
521	        let others: usize = (0..n).filter(|&j| j != i).map(|j| occ[j]).sum();
522	        let budget = full.saturating_sub(others).max(MIN_CELL_BUDGET);
523	        out[i] = budget;
524	        occ[i] = widths[i].min(budget);
525	    }
526	    out
527	}
528	
529	/// Wrap every cell of one record group, sharing the group [`FILL_WIDTH`] via
530	/// [`group_widths`] and laying each cell out at its width with the faithful engine.
531	fn group_cells(flat_cells: &[String], ports: &[String]) -> Vec<Cell> {
532	    let widths: Vec<usize> = flat_cells.iter().map(|t| t.chars().count()).collect();
533	    let fills = group_widths(&widths);
534	    flat_cells
535	        .iter()
536	        .zip(ports)
537	        .zip(fills)
538	        .map(|((text, p), w)| Cell::new(p.clone(), wrap_cell_dot(text, w as isize)))
539	        .collect()
540	}
