543	fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
544	    match r {
545	        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
546	        EndRef::Conclusion(n, c) => {
