1	//! Reconstructing how a record cell's flat term text is fed through the layout
2	//! engine ([`crate::pretty`]).
3	//!
4	//! The engine ([`crate::pretty`]) is the reference toolchain's BSD pretty-printer,
5	//! ported faithfully. This module carries the tamarin-SPECIFIC part: which
6	//! combinators wrap a fact / tuple / info cell, with what padding, and at what
7	//! line width — every one of which was pinned by black-box probes (BEHAVIOR.md
8	//! §3f; QUERIES.log wrap sweeps E10..E14 / W69..W74 and the Wide-rule case graph).
9	//!
10	//! Reconstructed cell grammar (each byte-verified against captured fixtures):
11	//!   * **fact / relation cell** `Name( a, b, … )` — the arguments are laid out as
12	//!     a `fsep` (paragraph fill, comma-punctuated) that opens after `Name( ` and
13	//!     self-aligns its continuation lines to that column; the whole thing is an
14	//!     outer `sep [ Name( args , ) ]` so the closing `)` drops to column 0 on its
15	//!     own line exactly when the argument fill wrapped (the ` )` padding space is
16	//!     the break). Zero-argument facts render `Name( )` flat.
17	//!   * **tuple** `<e1, …, en>` — `'<' <> fcat(e1, ", ", …, en, nest(-1) '>')`: the
18	//!     elements fill (paragraph, `, `-punctuated) and self-align one column past
19	//!     the `<`; the closing `>` is a fill element nested back one column, so it
20	//!     stays beside the last element when it fits and otherwise peels onto its own
21	//!     line aligned under the `<`.
22	//!   * **info cell** `#t : Rule[a1, …]` — the action list is a `vcat` (one action
23	//!     per line) wrapped in `[ … ]`; with two or more actions it is therefore
24	//!     always vertical, and a lone action fills only when the cell overflows.
25	//!
26	//! The line WIDTH a cell is laid out at is [`crate::pretty::render_page`]'s line
27	//! length; for a lone cell it is [`FILL_WIDTH`] (= 87, the probed flat-fit
28	//! boundary). How the cells of one record group share that width is a separate,
29	//! probe-derived allocation and lives in [`crate::generate`].
30	
31	use crate::pretty::{beside_op, char as pchar, fcat, fsep, nest, render_page, sep, text, vcat, Doc};
32	
33	/// Line length the reference lays a lone record cell out at (BEHAVIOR.md §3f): a
34	/// fact whose flat rendering is `≤ 87` columns stays on one line, `88` breaks.
35	pub const FILL_WIDTH: isize = 87;
36	
37	/// Ribbons-per-line the reference uses for cell layout. The probed boundary is a
38	/// single absolute column budget measured from column 0, i.e. `min(lineLength,
39	/// ribbon) == lineLength`, so ribbon does not bind — modelled as `1.0`.
40	pub const RIBBONS: f64 = 1.0;
41	
42	/// Split `s` at top-level `", "` separators, honoring `()`/`<>`/`[]` nesting and
43	/// `'…'` quotes. Returns the comma-separated pieces (each un-trimmed).
44	pub fn split_top_commas(s: &str) -> Vec<String> {
45	    let chars: Vec<char> = s.chars().collect();
46	    let mut parts: Vec<String> = Vec::new();
47	    let mut cur = String::new();
48	    let mut depth = 0i32;
49	    let mut in_quote = false;
50	    let mut i = 0;
51	    while i < chars.len() {
52	        let c = chars[i];
53	        if in_quote {
54	            cur.push(c);
55	            if c == '\'' {
56	                in_quote = false;
57	            }
58	            i += 1;
59	            continue;
60	        }
61	        match c {
62	            '\'' => {
63	                in_quote = true;
64	                cur.push(c);
65	                i += 1;
66	            }
67	            '(' | '<' | '[' => {
68	                depth += 1;
69	                cur.push(c);
70	                i += 1;
71	            }
72	            ')' | '>' | ']' => {
73	                depth -= 1;
74	                cur.push(c);
75	                i += 1;
76	            }
77	            ',' if depth == 0 && i + 1 < chars.len() && chars[i + 1] == ' ' => {
78	                parts.push(std::mem::take(&mut cur));
79	                i += 2;
80	            }
81	            _ => {
82	                cur.push(c);
83	                i += 1;
84	            }
85	        }
86	    }
87	    parts.push(cur);
88	    parts
89	}
