91	/// Count top-level actions in an info action list `#t : Rule[ … ]` (0 if none).
92	pub fn count_info_actions(flat: &str) -> usize {
93	    let Some(open) = flat.find('[') else { return 0 };
94	    let inner = &flat[open + 1..];
95	    let inner = inner.strip_suffix(']').unwrap_or(inner);
96	    if inner.is_empty() {
97	        return 0;
98	    }
99	    split_top_commas(inner).len()
100	}
