105	
106	/// A `Doc` for one tuple element / fact argument. Tuples recurse; every other
107	/// shape (atom, function application, exponentiation, AC term) is a single fill
108	/// token rendered from its flat text (these do not re-wrap internally in the
109	/// observed cells — the wrap happens at the enclosing fact/tuple level).
110	fn arg_doc(s: &str) -> Doc {
111	    if is_tuple(s) {
112	        tuple_doc(&s[1..s.len() - 1])
113	    } else {
114	        text(s)
115	    }
116	}
117	
118	/// `<e1, …, en>` — the elements fill and align one past the `<`; the `>` is a
119	/// fill element nested back one column so it stays beside the last element when
120	/// it fits and peels under the `<` otherwise.
121	fn tuple_doc(inner: &str) -> Doc {
122	    let elems = split_top_commas(inner);
123	    let n = elems.len();
124	    let mut toks: Vec<Doc> = Vec::with_capacity(n + 1);
125	    for (i, e) in elems.iter().enumerate() {
126	        let d = arg_doc(e);
127	        if i + 1 < n {
128	            toks.push(beside_op(d, text(", ")));
129	        } else {
130	            toks.push(d);
131	        }
132	    }
133	    toks.push(nest(-1, &pchar('>')));
134	    beside_op(pchar('<'), fcat(toks))
135	}
136	
137	/// `Name( a, b, … )` — the argument list is a comma-punctuated `fsep` opening
138	/// after `Name( `; the outer `sep [ …, ) ]` drops the closing `)` to its own line
139	/// exactly when the argument fill wraps.
140	fn fact_doc(name: &str, args: &[String]) -> Doc {
141	    if args.is_empty() {
142	        return text(&format!("{}( )", name));
143	    }
144	    let n = args.len();
145	    let toks: Vec<Doc> = args
146	        .iter()
147	        .enumerate()
148	        .map(|(i, a)| {
149	            let d = arg_doc(a);
150	            if i + 1 < n {
151	                beside_op(d, text(","))
152	            } else {
153	                d
154	            }
155	        })
156	        .collect();
157	    let args_doc = fsep(toks);
158	    let opened = beside_op(text(&format!("{}( ", name)), args_doc);
159	    sep(vec![opened, text(")")])
160	}
161	
162	/// `#t : Rule[a1, …]` — the action list is a `vcat` (one action per line) inside
163	/// `[ … ]`; `#t : Rule` with no actions is bare text.
164	fn info_doc(flat: &str) -> Doc {
165	    let Some(open) = flat.find('[') else {
166	        return text(flat);
167	    };
168	    if !flat.ends_with(']') {
169	        return text(flat);
170	    }
171	    let prefix = &flat[..open + 1]; // "#t : Rule["
172	    let inner = &flat[open + 1..flat.len() - 1];
173	    let actions = split_top_commas(inner);
174	    let n = actions.len();
175	    let action_docs: Vec<Doc> = actions
176	        .iter()
177	        .enumerate()
178	        .map(|(i, a)| {
179	            // Each action is a fact that may itself fill-wrap; non-final actions
180	            // carry a trailing comma.
181	            let d = fact_from_flat(a);
182	            if i + 1 < n {
183	                beside_op(d, text(","))
184	            } else {
185	                d
186	            }
187	        })
188	        .collect();
189	    beside_op(beside_op(text(prefix), vcat(action_docs)), text("]"))
190	}
191	
192	/// Build a fact `Doc` from a flat fact string `Name( … )` (or a bare atom).
193	fn fact_from_flat(flat: &str) -> Doc {
194	    if let Some((name, args)) = parse_fact(flat) {
195	        fact_doc(name, &args)
196	    } else {
197	        text(flat)
198	    }
199	}
200	
201	/// Parse a padded fact `Name( a, b )` / `Name( )` into `(name, args)`. Returns
202	/// `None` for anything that is not a padded fact (an atom, a function `f(x)`
203	/// without inner padding, etc.).
204	fn parse_fact(flat: &str) -> Option<(&str, Vec<String>)> {
205	    if flat == "" {
206	        return None;
207	    }
208	    // Zero-arg: "Name( )"
209	    if let Some(name) = flat.strip_suffix("( )") {
210	        if !name.is_empty() && !name.contains(['(', ')', '<', '>', ' ']) {
211	            return Some((name, Vec::new()));
212	        }
213	    }
214	    let open = flat.find("( ")?;
215	    if !flat.ends_with(" )") {
216	        return None;
217	    }
218	    let name = &flat[..open];
219	    // The name must be a plain relation/fact symbol (optionally `!`-prefixed).
220	    if name.is_empty()
221	        || name.contains(['(', ')', '<', '>', ' ', ','])
222	    {
223	        return None;
224	    }
225	    let content = &flat[open + 2..flat.len() - 2];
226	    Some((name, split_top_commas(content)))
227	}
228	
229	/// Build a `Doc` for one record cell from its flat (post-abbreviation,
230	/// un-escaped) text, dispatching by cell shape (info / fact / atom).
231	pub fn cell_doc(flat: &str) -> Doc {
232	    if flat.starts_with('#') && flat.contains('[') {
233	        info_doc(flat)
234	    } else if let Some((name, args)) = parse_fact(flat) {
235	        fact_doc(name, &args)
236	    } else {
237	        text(flat)
238	    }
239	}
240	
241	/// Render a cell's flat text to physical lines `(indent, content)` at the given
242	/// line width, via the layout engine. `indent` is the count of leading spaces the
243	/// engine emitted (→ `&nbsp;` in the record label); `content` is the line with
244	/// that indentation stripped, still un-escaped.
245	pub fn layout_lines(flat: &str, width: isize) -> Vec<(usize, String)> {
246	    let doc = cell_doc(flat);
247	    let rendered = render_page(width, RIBBONS, &doc);
248	    rendered
249	        .split('\n')
250	        .map(|line| {
251	            let indent = line.len() - line.trim_start_matches(' ').len();
252	            (indent, line[indent..].to_string())
253	        })
254	        .collect()
255	}
256	
257	/// Render a cell's flat text into the exact graphviz record-label bytes at the
258	/// given line width: a single escaped line when it fits, otherwise each physical
259	/// line prefixed by its `&nbsp;` indent, escaped, and terminated by `\l`
260	/// (trailing `\l` included), per BEHAVIOR.md §3f. The layout is computed on the
261	/// UN-escaped text (so `<`/`>` count one column each, matching the reference),
262	/// and escaping is applied afterwards.
263	pub fn wrap_cell_dot(flat: &str, width: isize) -> String {
264	    let lines = layout_lines(flat, width);
265	    if lines.len() == 1 && lines[0].0 == 0 {
266	        return crate::render::escape_record(&lines[0].1);
267	    }
268	    let mut out = String::new();
269	    for (indent, content) in &lines {
270	        out.push_str(&"&nbsp;".repeat(*indent));
271	        out.push_str(&crate::render::escape_record(content));
272	        out.push_str("\\l");
273	    }
274	    out
275	}
