1	//! A faithful Rust port of the Hughes/Peyton-Jones pretty-printing library
2	//! `Text.PrettyPrint.HughesPJ` (Haskell `pretty` 1.1.3.6, BSD-licensed), the
3	//! layout engine the reference toolchain (GHC boot library) uses to render
4	//! record-cell term text.
5	//!
6	//! This module implements the `Doc` document model and the combinators, the
7	//! best/fits layout selection, and the `PageMode` renderer, following the
8	//! sanctioned BSD source (`sanctioned/pretty-1.1.3.6/src/Text/PrettyPrint/
9	//! Annotated/HughesPJ.hs`) semantics precisely: `<>`/`<+>`, `$$`/`$+$`,
10	//! `hcat`/`hsep`/`vcat`, `sep`/`cat`, `fsep`/`fcat`, `nest`/`hang`, and the
11	//! `best`/`nicest`/`fits` fitting logic with `lineLength` and `ribbonsPerLine`.
12	//!
13	//! Nothing in this file is tamarin-specific: it is the general layout algebra.
14	//! WHICH combinators tamarin applies to a record cell, and with what line width
15	//! / ribbon / indent, is derived from black-box probes and lives in
16	//! [`crate::doclayout`]; this module is the exact engine those parameters feed.
17	//!
18	//! The annotation machinery of the original is elided (this port renders to a
19	//! plain `String`), so `TextBeside` carries the text and its column width
20	//! directly instead of an `AnnotDetails`.
21	
22	use std::rc::Rc;
23	
24	/// The abstract document type. A `Doc` denotes a *set* of layouts; a `Doc` with
25	/// no `Union`/`NoDoc` denotes a single layout. Mirrors the Haskell `Doc a`
26	/// constructors (annotations elided).
27	#[derive(Clone, Debug)]
28	pub enum Doc {
29	    /// An empty span (`empty`): no height, no width.
30	    Empty,
31	    /// `text "" $$ x` — a newline above `x`. Its argument is never `Empty`.
32	    NilAbove(Rc<Doc>),
33	    /// `text s <> x` — literal text (with its column width) beside `x`. The
34	    /// argument is never a `Nest`.
35	    TextBeside(Rc<str>, usize, Rc<Doc>),
36	    /// `nest k x` — indent `x` by `k` columns (`k` may be negative).
37	    Nest(isize, Rc<Doc>),
38	    /// `ul \`union\` ur` — a choice between two layouts that flatten equal.
39	    Union(Rc<Doc>, Rc<Doc>),
40	    /// The empty *set* of documents.
41	    NoDoc,
42	    /// `Beside l sep r` — `sep` = true means a space is inserted between.
43	    Beside(Rc<Doc>, bool, Rc<Doc>),
44	    /// `Above u never_overlap l` — `never_overlap` = true forbids overlap.
45	    Above(Rc<Doc>, bool, Rc<Doc>),
46	}
47	
48	use Doc::*;
49	
50	fn rc(d: Doc) -> Rc<Doc> {
51	    Rc::new(d)
52	}
53	
54	// ---------------------------------------------------------------------------
55	// Constructors (§ "Values and Predicates")
56	
57	/// A one-character document.
58	pub fn char(c: char) -> Doc {
59	    let mut buf = [0u8; 4];
60	    let s: &str = c.encode_utf8(&mut buf);
61	    TextBeside(Rc::from(s), 1, rc(Empty))
62	}
63	
64	/// A one-line literal string document; its width is its Unicode-scalar count.
65	pub fn text(s: &str) -> Doc {
66	    let len = s.chars().count();
67	    TextBeside(Rc::from(s), len, rc(Empty))
68	}
69	
70	/// Text with an explicit column width (`sizedText l s`); use width 0 for
71	/// non-printing text.
72	pub fn sized_text(len: usize, s: &str) -> Doc {
73	    TextBeside(Rc::from(s), len, rc(Empty))
74	}
75	
76	/// The empty document (identity for `<>`, `$$`, and list combinators).
77	pub fn empty() -> Doc {
78	    Empty
79	}
80	
81	/// Is this the empty document?
82	pub fn is_empty(d: &Doc) -> bool {
83	    matches!(d, Empty)
84	}
85	
86	fn space_text() -> Doc {
87	    TextBeside(Rc::from(" "), 1, rc(Empty))
88	}
89	
90	// ---------------------------------------------------------------------------
91	// Structural smart-constructors
92	
93	fn nil_above_(d: Rc<Doc>) -> Doc {
94	    NilAbove(d)
95	}
96	
97	fn text_beside_(s: Rc<str>, l: usize, d: Rc<Doc>) -> Doc {
98	    TextBeside(s, l, d)
99	}
100	
101	fn nest_(k: isize, d: Rc<Doc>) -> Doc {
102	    Nest(k, d)
103	}
104	
105	fn union_(a: Rc<Doc>, b: Rc<Doc>) -> Doc {
106	    Union(a, b)
107	}
108	
109	/// `reduceDoc`: push `Beside`/`Above` down into reduced form (RDoc).
110	pub fn reduce_doc(d: &Doc) -> Doc {
111	    match d {
112	        Beside(p, g, q) => beside(p, *g, &reduce_doc(q)),
113	        Above(p, g, q) => above(p, *g, &reduce_doc(q)),
114	        other => other.clone(),
115	    }
116	}
117	
118	fn reduce_rc(d: &Doc) -> Rc<Doc> {
119	    rc(reduce_doc(d))
120	}
121	
122	// ---------------------------------------------------------------------------
123	// nest / mkNest / mkUnion
124	
125	/// `nest k p` — indent by `k` (may be negative).
126	pub fn nest(k: isize, p: &Doc) -> Doc {
127	    mk_nest(k, &reduce_doc(p))
128	}
129	
130	fn mk_nest(k: isize, d: &Doc) -> Doc {
131	    match d {
132	        Nest(k1, p) => mk_nest(k + k1, p),
133	        NoDoc => NoDoc,
134	        Empty => Empty,
135	        _ if k == 0 => d.clone(),
136	        _ => nest_(k, rc(d.clone())),
137	    }
138	}
139	
140	fn mk_union(p: Doc, q: Doc) -> Doc {
141	    match p {
142	        Empty => Empty,
143	        _ => union_(rc(p), rc(q)),
144	    }
145	}
146	
147	// ---------------------------------------------------------------------------
148	// Horizontal composition <> and <+>
149	
150	/// `p <> q` — beside.
151	pub fn beside_op(p: Doc, q: Doc) -> Doc {
152	    beside_(p, false, q)
153	}
154	
155	/// `p <+> q` — beside, separated by a space unless an argument is empty.
156	pub fn beside_space(p: Doc, q: Doc) -> Doc {
157	    beside_(p, true, q)
158	}
159	
160	fn beside_(p: Doc, g: bool, q: Doc) -> Doc {
161	    match (&p, &q) {
162	        (_, Empty) => p,
163	        (Empty, _) => q,
164	        _ => Beside(rc(p), g, rc(q)),
165	    }
166	}
167	
168	/// `beside p g q` (spec: `p <g> q`) over reduced docs.
169	fn beside(p: &Doc, g: bool, q: &Doc) -> Doc {
170	    match p {
171	        NoDoc => NoDoc,
172	        Union(p1, p2) => union_(rc(beside(p1, g, q)), rc(beside(p2, g, q))),
173	        Empty => q.clone(),
174	        Nest(k, p1) => nest_(*k, rc(beside(p1, g, q))),
175	        Beside(p1, g1, q1) => {
176	            if *g1 == g {
177	                beside(p1, *g1, &beside(q1, g, q))
178	            } else {
179	                beside(&reduce_doc(p), g, q)
180	            }
181	        }
182	        Above(..) => beside(&reduce_doc(p), g, q),
183	        NilAbove(p1) => nil_above_(rc(beside(p1, g, q))),
184	        TextBeside(s, l, p1) => {
185	            let rest = match p1.as_ref() {
186	                Empty => nil_beside(g, q),
187	                _ => beside(p1, g, q),
188	            };
189	            text_beside_(s.clone(), *l, rc(rest))
190	        }
191	    }
192	}
193	
194	/// `nilBeside g p` (spec: `text "" <g> p`).
195	fn nil_beside(g: bool, p: &Doc) -> Doc {
196	    match p {
197	        Empty => Empty,
198	        Nest(_, p1) => nil_beside(g, p1),
199	        _ => {
200	            if g {
201	                TextBeside(Rc::from(" "), 1, rc(p.clone()))
202	            } else {
203	                p.clone()
204	            }
205	        }
206	    }
207	}
208	
209	// ---------------------------------------------------------------------------
210	// Vertical composition $$ and $+$
211	
212	/// `p $$ q` — above, with overlap allowed.
213	pub fn above_op(p: Doc, q: Doc) -> Doc {
214	    above_(p, false, q)
215	}
216	
217	/// `p $+$ q` — above, no overlap.
218	pub fn above_plus(p: Doc, q: Doc) -> Doc {
219	    above_(p, true, q)
220	}
221	
222	fn above_(p: Doc, g: bool, q: Doc) -> Doc {
223	    match (&p, &q) {
224	        (_, Empty) => p,
225	        (Empty, _) => q,
226	        _ => Above(rc(p), g, rc(q)),
227	    }
228	}
229	
230	fn above(p: &Doc, g: bool, q: &Doc) -> Doc {
231	    match p {
232	        Above(p1, g1, q1) => above(p1, *g1, &above(q1, g, q)),
233	        Beside(..) => above_nest(&reduce_doc(p), g, 0, &reduce_doc(q)),
234	        _ => above_nest(p, g, 0, &reduce_doc(q)),
235	    }
236	}
237	
238	/// `aboveNest p g k q` (spec: `p $g$ (nest k q)`).
239	fn above_nest(p: &Doc, g: bool, k: isize, q: &Doc) -> Doc {
240	    match p {
241	        NoDoc => NoDoc,
242	        Union(p1, p2) => union_(
243	            rc(above_nest(p1, g, k, q)),
244	            rc(above_nest(p2, g, k, q)),
245	        ),
246	        Empty => mk_nest(k, q),
247	        Nest(k1, p1) => nest_(*k1, rc(above_nest(p1, g, k - k1, q))),
248	        NilAbove(p1) => nil_above_(rc(above_nest(p1, g, k, q))),
249	        TextBeside(s, l, p1) => {
250	            let k1 = k - (*l as isize);
251	            let rest = match p1.as_ref() {
252	                Empty => nil_above_nest(g, k1, q),
253	                _ => above_nest(p1, g, k1, q),
254	            };
255	            text_beside_(s.clone(), *l, rc(rest))
256	        }
257	        Above(..) => panic!("aboveNest Above"),
258	        Beside(..) => panic!("aboveNest Beside"),
259	    }
260	}
261	
262	/// `nilAboveNest g k q` (spec: `text s <> (text "" $g$ nest k q)`).
263	fn nil_above_nest(g: bool, k: isize, q: &Doc) -> Doc {
264	    match q {
265	        Empty => Empty,
266	        Nest(k1, q1) => nil_above_nest(g, k + k1, q1),
267	        _ => {
268	            if !g && k > 0 {
269	                let ind = indent(k);
270	                let len = ind.chars().count();
271	                text_beside_(Rc::from(ind.as_str()), len, rc(q.clone()))
272	            } else {
273	                nil_above_(rc(mk_nest(k, q)))
274	            }
275	        }
276	    }
277	}
278	
279	// ---------------------------------------------------------------------------
280	// List versions: hcat / hsep / vcat  (via reduceHoriz/reduceVert)
281	
282	#[derive(Clone, Copy)]
283	enum IsEmpty {
284	    Empty,
285	    NotEmpty,
286	}
287	
288	fn reduce_horiz(d: &Doc) -> (IsEmpty, Doc) {
289	    match d {
290	        Beside(p, g, q) => {
291	            let (_, pr) = reduce_horiz(p);
292	            eliminate_empty(true, pr, *g, reduce_horiz(q))
293	        }
294	        _ => (IsEmpty::NotEmpty, d.clone()),
295	    }
296	}
297	
298	fn reduce_vert(d: &Doc) -> (IsEmpty, Doc) {
299	    match d {
300	        Above(p, g, q) => {
301	            let (_, pr) = reduce_vert(p);
302	            eliminate_empty(false, pr, *g, reduce_vert(q))
303	        }
304	        _ => (IsEmpty::NotEmpty, d.clone()),
305	    }
306	}
