308	/// `beside_cons` = true builds `Beside`, false builds `Above`.
309	fn eliminate_empty(beside_cons: bool, p: Doc, g: bool, q: (IsEmpty, Doc)) -> (IsEmpty, Doc) {
310	    match p {
311	        Empty => q,
312	        _ => {
313	            let out = match q {
314	                (IsEmpty::NotEmpty, q1) => {
315	                    if beside_cons {
316	                        Beside(rc(p), g, rc(q1))
317	                    } else {
318	                        Above(rc(p), g, rc(q1))
319	                    }
320	                }
321	                (IsEmpty::Empty, _) => p,
322	            };
323	            (IsEmpty::NotEmpty, out)
324	        }
325	    }
326	}
