376	// sep / cat
377	
378	/// `sep` — either `hsep` (one line) or `vcat`.
379	pub fn sep(ds: Vec<Doc>) -> Doc {
380	    sep_x(true, ds)
381	}
382	
383	/// `cat` — either `hcat` (one line) or `vcat`.
384	pub fn cat(ds: Vec<Doc>) -> Doc {
385	    sep_x(false, ds)
386	}
387	
388	fn sep_x(x: bool, ds: Vec<Doc>) -> Doc {
389	    if ds.is_empty() {
390	        return Empty;
391	    }
392	    let mut it = ds.into_iter();
393	    let p = it.next().unwrap();
394	    let ys: Vec<Doc> = it.collect();
395	    sep1(x, &reduce_doc(&p), 0, &ys)
396	}
397	
398	fn sep1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
399	    match p {
400	        NoDoc => NoDoc,
401	        Union(p1, q) => union_(
402	            rc(sep1(g, p1, k, ys)),
403	            rc(above_nest(q, false, k, &reduce_doc(&vcat(ys.to_vec())))),
404	        ),
405	        Empty => mk_nest(k, &sep_x(g, ys.to_vec())),
406	        Nest(n, p1) => nest_(*n, rc(sep1(g, p1, k - n, ys))),
407	        NilAbove(p1) => nil_above_(rc(above_nest(
408	            p1,
409	            false,
410	            k,
411	            &reduce_doc(&vcat(ys.to_vec())),
412	        ))),
413	        TextBeside(s, l, p1) => {
414	            text_beside_(s.clone(), *l, rc(sep_nb(g, p1, k - (*l as isize), ys)))
415	        }
416	        Above(..) => panic!("sep1 Above"),
417	        Beside(..) => panic!("sep1 Beside"),
418	    }
419	}
420	
421	fn sep_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
422	    match p {
423	        Nest(_, p1) => sep_nb(g, p1, k, ys),
424	        Empty => {
425	            let rest = if g {
426	                hsep(ys.to_vec())
427	            } else {
428	                hcat(ys.to_vec())
429	            };
430	            let left = one_liner(&nil_beside(g, &reduce_doc(&rest)));
431	            let right = nil_above_nest(false, k, &reduce_doc(&vcat(ys.to_vec())));
432	            mk_union(left, right)
433	        }
434	        _ => sep1(g, p, k, ys),
435	    }
436	}
