438	// ---------------------------------------------------------------------------
439	// fill (fcat / fsep)
440	
441	/// `fcat` — paragraph-fill version of `cat` (no inter-element space).
442	pub fn fcat(ds: Vec<Doc>) -> Doc {
443	    fill(false, ds)
444	}
445	
446	/// `fsep` — paragraph-fill version of `sep` (space between elements).
447	pub fn fsep(ds: Vec<Doc>) -> Doc {
448	    fill(true, ds)
449	}
450	
451	fn fill(g: bool, ds: Vec<Doc>) -> Doc {
452	    if ds.is_empty() {
453	        return Empty;
454	    }
455	    let mut it = ds.into_iter();
456	    let p = it.next().unwrap();
457	    let ys: Vec<Doc> = it.collect();
458	    fill1(g, &reduce_doc(&p), 0, &ys)
459	}
460	
461	fn fill1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
462	    match p {
463	        NoDoc => NoDoc,
464	        Union(p1, q) => union_(
465	            rc(fill1(g, p1, k, ys)),
466	            rc(above_nest(q, false, k, &fill(g, ys.to_vec()))),
467	        ),
468	        Empty => mk_nest(k, &fill(g, ys.to_vec())),
469	        Nest(n, p1) => nest_(*n, rc(fill1(g, p1, k - n, ys))),
470	        NilAbove(p1) => nil_above_(rc(above_nest(p1, false, k, &fill(g, ys.to_vec())))),
471	        TextBeside(s, l, p1) => {
472	            text_beside_(s.clone(), *l, rc(fill_nb(g, p1, k - (*l as isize), ys)))
473	        }
474	        Above(..) => panic!("fill1 Above"),
475	        Beside(..) => panic!("fill1 Beside"),
476	    }
477	}
478	
479	fn fill_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
480	    match p {
481	        Nest(_, p1) => fill_nb(g, p1, k, ys),
482	        Empty => {
483	            if ys.is_empty() {
484	                Empty
485	            } else if matches!(ys[0], Empty) {
486	                fill_nb(g, &Empty, k, &ys[1..])
487	            } else {
488	                fill_nbe(g, k, &ys[0], &ys[1..])
489	            }
490	        }
491	        _ => fill1(g, p, k, ys),
492	    }
493	}
494	
495	fn fill_nbe(g: bool, k: isize, y: &Doc, ys: &[Doc]) -> Doc {
496	    let k1 = if g { k - 1 } else { k };
497	    let y_one = elide_nest(&one_liner(&reduce_doc(y)));
498	    let left = nil_beside(g, &fill1(g, &y_one, k1, ys));
499	    let mut rest = vec![y.clone()];
500	    rest.extend_from_slice(ys);
501	    let right = nil_above_nest(false, k, &fill(g, rest));
502	    mk_union(left, right)
503	}
504	
505	fn elide_nest(d: &Doc) -> Doc {
506	    match d {
507	        Nest(_, d1) => d1.as_ref().clone(),
508	        _ => d.clone(),
509	    }
510	}
