512	// ---------------------------------------------------------------------------
513	// Best layout: best / nicest / fits / oneLiner
514	
515	fn one_liner(d: &Doc) -> Doc {
516	    match d {
517	        NoDoc => NoDoc,
518	        Empty => Empty,
519	        NilAbove(_) => NoDoc,
520	        TextBeside(s, l, p) => text_beside_(s.clone(), *l, rc(one_liner(p))),
521	        Nest(k, p) => nest_(*k, rc(one_liner(p))),
522	        Union(p, _) => one_liner(p),
523	        Above(..) => panic!("oneLiner Above"),
524	        Beside(..) => panic!("oneLiner Beside"),
525	    }
526	}
527	
528	/// `best w r doc` — resolve unions to a single layout for line width `w`,
529	/// ribbon width `r`. This is a strict but semantically faithful rendering of
530	/// the Haskell lazy `best`/`nicest1`: at a `Union` the left branch is resolved
531	/// and kept iff its first line fits; the right is resolved only otherwise.
532	fn best(w: isize, r: isize, d: &Doc) -> Doc {
533	    get(w, r, d)
534	}
535	
536	fn get(w: isize, r: isize, d: &Doc) -> Doc {
537	    match d {
538	        Empty => Empty,
539	        NoDoc => NoDoc,
540	        NilAbove(p) => nil_above_(rc(get(w, r, p))),
541	        TextBeside(s, l, p) => text_beside_(s.clone(), *l, rc(get1(w, r, *l as isize, p))),
542	        Nest(k, p) => nest_(*k, rc(get(w - k, r, p))),
543	        Union(p, q) => nicest(w, r, p, q),
544	        Above(..) => panic!("best get Above"),
545	        Beside(..) => panic!("best get Beside"),
546	    }
547	}
548	
549	fn get1(w: isize, r: isize, sl: isize, d: &Doc) -> Doc {
550	    match d {
551	        Empty => Empty,
552	        NoDoc => NoDoc,
553	        NilAbove(p) => nil_above_(rc(get(w - sl, r, p))),
554	        TextBeside(s, l, p) => {
555	            text_beside_(s.clone(), *l, rc(get1(w, r, sl + *l as isize, p)))
556	        }
557	        Nest(_, p) => get1(w, r, sl, p),
558	        Union(p, q) => nicest1(w, r, sl, p, q),
559	        Above(..) => panic!("best get1 Above"),
560	        Beside(..) => panic!("best get1 Beside"),
561	    }
562	}
563	
564	fn nicest(w: isize, r: isize, p: &Doc, q: &Doc) -> Doc {
565	    nicest1(w, r, 0, p, q)
566	}
567	
568	fn nicest1(w: isize, r: isize, sl: isize, p: &Doc, q: &Doc) -> Doc {
569	    // Resolve the left branch; keep it iff its first line fits. Only resolve the
570	    // right branch if the left does not fit (matching the Haskell laziness).
571	    let lp = get1(w, r, sl, p);
572	    if fits(w.min(r) - sl, &lp) {
573	        lp
574	    } else {
575	        get1(w, r, sl, q)
576	    }
577	}
578	
579	/// True iff the *first line* of `d` fits in `n` columns.
580	fn fits(n: isize, d: &Doc) -> bool {
581	    if n < 0 {
582	        return false;
583	    }
584	    match d {
585	        NoDoc => false,
586	        Empty => true,
587	        NilAbove(_) => true,
588	        TextBeside(_, l, p) => fits(n - *l as isize, p),
589	        Above(..) => panic!("fits Above"),
590	        Beside(..) => panic!("fits Beside"),
591	        Union(..) => panic!("fits Union"),
592	        Nest(..) => panic!("fits Nest"),
593	    }
594	}
