597	// Rendering (PageMode only)
598	
599	fn indent(n: isize) -> String {
600	    if n <= 0 {
601	        String::new()
602	    } else {
603	        " ".repeat(n as usize)
604	    }
605	}
606	
607	/// Banker's-rounding of `line_len / ribbons` to match Haskell `round`.
608	fn round_ribbon(line_len: isize, ribbons: f64) -> isize {
609	    let v = line_len as f64 / ribbons;
610	    let floor = v.floor();
611	    let diff = v - floor;
612	    let rounded = if (diff - 0.5).abs() < 1e-9 {
613	        // round half to even
614	        let f = floor as i64;
615	        if f % 2 == 0 {
616	            f
617	        } else {
618	            f + 1
619	        }
620	    } else {
621	        v.round() as i64
622	    };
623	    rounded as isize
624	}
625	
626	/// Render a document in `PageMode` at line length `line_len` and
627	/// `ribbons_per_line`, producing the plain string (newline-separated lines,
628	/// each continuation prefixed by its indentation spaces).
629	pub fn render_page(line_len: isize, ribbons_per_line: f64, doc: &Doc) -> String {
630	    let ribbon_len = round_ribbon(line_len, ribbons_per_line);
631	    let reduced = reduce_doc(doc);
632	    let best_doc = best(line_len, ribbon_len, &reduced);
633	    display_page(line_len, ribbon_len, &best_doc)
634	}
635	
636	fn display_page(page_width: isize, ribbon_width: isize, doc: &Doc) -> String {
637	    let _gap = page_width - ribbon_width;
638	    let mut out = String::new();
639	    lay(&mut out, 0, doc);
640	    out
641	}
642	
643	fn lay(out: &mut String, k: isize, d: &Doc) {
644	    match d {
645	        Nest(k1, p) => lay(out, k + k1, p),
646	        Empty => {}
647	        NilAbove(p) => {
648	            out.push('\n');
649	            lay(out, k, p);
650	        }
651	        TextBeside(s, l, p) => lay1(out, k, s, *l, p),
652	        Above(..) => panic!("display lay Above"),
653	        Beside(..) => panic!("display lay Beside"),
654	        NoDoc => panic!("display lay NoDoc"),
655	        Union(..) => panic!("display lay Union"),
656	    }
657	}
658	
659	fn lay1(out: &mut String, k: isize, s: &str, l: usize, p: &Doc) {
660	    out.push_str(&indent(k));
661	    out.push_str(s);
662	    lay2(out, k + l as isize, p);
663	}
664	
665	fn lay2(out: &mut String, k: isize, d: &Doc) {
666	    match d {
667	        NilAbove(p) => {
668	            out.push('\n');
669	            lay(out, k, p);
670	        }
671	        TextBeside(s, l, p) => {
672	            out.push_str(s);
673	            lay2(out, k + *l as isize, p);
674	        }
675	        Nest(_, p) => lay2(out, k, p),
676	        Empty => {}
677	        Above(..) => panic!("display lay2 Above"),
678	        Beside(..) => panic!("display lay2 Beside"),
679	        NoDoc => panic!("display lay2 NoDoc"),
680	        Union(..) => panic!("display lay2 Union"),
681	    }
682	}
