//! Corpus census of the record-cell wrap model (BEHAVIOR.md §3f).
//!
//! For every record in the corpus, parse its label into groups → cells, dewrap
//! each cell back to its flat (post-abbreviation) text, re-run the crate's group
//! layout, and compare the produced record-label bytes to the actual cell bytes.
//! Reports the byte-exactness over wrapping prem/concl cells (the metric the
//! round-8 task tracks) and over all cells.
//!
//! Ignored by default; run with `GRAPHCLEAN_CORPUS=<dir> cargo test --test
//! fill_census -- --ignored --nocapture`.

use graph_clean::doclayout::wrap_cell_dot;
use graph_clean::generate::group_widths;

/// Split `s` on top-level `sep`, respecting graphviz record `{ }` nesting and
/// `\`-escapes (a `\<`/`\>`/`\{`/`\}`/`\|` pair is opaque). Mirrors vc_fill.py.
fn split_top(s: &str, sep: char) -> Vec<String> {
    let chars: Vec<char> = s.chars().collect();
    let mut parts = Vec::new();
    let mut cur = String::new();
    let mut depth = 0i32;
    let mut i = 0;
    while i < chars.len() {
        let c = chars[i];
        if c == '\\' && i + 1 < chars.len() {
            cur.push(c);
            cur.push(chars[i + 1]);
            i += 2;
            continue;
        }
        match c {
            '{' => {
                depth += 1;
                cur.push(c);
            }
            '}' => {
                depth -= 1;
                cur.push(c);
            }
            _ if c == sep && depth == 0 => {
                parts.push(std::mem::take(&mut cur));
            }
            _ => cur.push(c),
        }
        i += 1;
    }
    parts.push(cur);
    parts
}

fn unescape(t: &str) -> String {
    t.replace("\\<", "<")
        .replace("\\>", ">")
        .replace("\\{", "{")
        .replace("\\}", "}")
        .replace("\\|", "|")
}

/// Parse a record label `{{c|c}|{c}|{c|c}}` into groups of raw cell strings
/// (each still carrying its `<nK> ` port prefix and any `\l`/`&nbsp;`). Returns
/// `None` if the label is not the expected nested-group shape.
fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
    if !(label.starts_with('{') && label.ends_with('}')) {
        return None;
    }
    let inner = &label[1..label.len() - 1];
    let mut groups = Vec::new();
    for g in split_top(inner, '|') {
        let g = g.trim();
        if !(g.starts_with('{') && g.ends_with('}')) {
            return None;
        }
        let gi = &g[1..g.len() - 1];
        let mut cells = Vec::new();
        for c in split_top(gi, '|') {
            cells.push(c);
        }
        groups.push(cells);
    }
    Some(groups)
}

/// Strip the `<nK> ` port prefix, returning the cell body (still wrapped).
fn strip_port(cell: &str) -> Option<&str> {
    let rest = cell.strip_prefix("<n")?;
    let sp = rest.find("> ")?;
    // ensure the bit between is all digits
    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) {
        return None;
    }
    Some(&rest[sp + 2..])
}

fn is_info_body(body: &str) -> bool {
    // "#<t> : ..." shape
    body.starts_with('#') && body.contains(" : ")
}

/// Reconstruct a cell's flat (post-abbreviation, un-escaped) text from its
/// wrapped body. Mirrors vc_fill.py `dewrap`.
fn dewrap(body: &str) -> String {
    let t = body.replace("&nbsp;", "");
    let t = t.replace(",\\l", ", "); // fact-arg / info break dropped the space
    let t = t.replace("\\l)", " )"); // fact ')' peel: flat had ' )'
    let t = t.replace("\\l", ""); // tuple '>' peel / tuple-elem break joins
    unescape(&t)
}

/// The cell's flat visual width (columns), reconstructed like vc_fill.py
/// `flat_width_cell`: unescape, drop `\l`/`&nbsp;`, add back one lost space per
/// `,\l` and per `\l)`.
fn flat_width(body: &str) -> usize {
    let lost = body.matches(",\\l").count() + body.matches("\\l)").count();
    let bare = unescape(&body.replace("\\l", "").replace("&nbsp;", ""));
    bare.chars().count() + lost
}

struct Tally {
    wrap_total: usize,
    wrap_match: usize,
    all_total: usize,
    all_match: usize,
    // mismatch buckets
    mism_examples: Vec<(String, String, String)>, // (flat, want, got)
}

fn run_model<F: Fn(&[usize]) -> Vec<usize>>(alloc: F, t: &mut Tally, corpus: &str) {
    for entry in std::fs::read_dir(corpus).unwrap() {
        let path = entry.unwrap().path();
        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
            continue;
        }
        let dot = std::fs::read_to_string(&path).unwrap();
        for line in dot.lines() {
            if !line.contains("shape=\"record\"") {
                continue;
            }
            // extract label="..."
            let Some(lstart) = line.find("label=\"") else { continue };
            let after = &line[lstart + 7..];
            let Some(lend) = after.find("\",fillcolor") else { continue };
            let label = &after[..lend];
            let Some(groups) = parse_record(label) else { continue };
            for cells in &groups {
                // bodies (port stripped)
                let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
                    Some(b) => b,
                    None => continue,
                };
                if bodies.len() == 1 && is_info_body(bodies[0]) {
                    continue; // info group handled separately
                }
                if bodies.iter().any(|b| is_info_body(b)) {
                    continue; // mixed / unexpected
                }
                let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
                let flat_texts: Vec<String> = bodies.iter().map(|b| dewrap(b)).collect();
                let widths = alloc(&flats);
                for (k, body) in bodies.iter().enumerate() {
                    let predicted = wrap_cell_dot(&flat_texts[k], widths[k] as isize);
                    let actual = body.to_string();
                    let is_wrap = body.contains("\\l");
                    t.all_total += 1;
                    if predicted == actual {
                        t.all_match += 1;
                    }
                    if is_wrap {
                        t.wrap_total += 1;
                        if predicted == actual {
                            t.wrap_match += 1;
                        } else if t.mism_examples.len() < 40 {
                            t.mism_examples.push((flat_texts[k].clone(), actual, predicted));
                        }
                    }
                }
            }
        }
    }
}

#[test]
#[ignore]
fn census() {
    let Ok(corpus) = std::env::var("GRAPHCLEAN_CORPUS") else {
        eprintln!("set GRAPHCLEAN_CORPUS");
        return;
    };
    let mut t = Tally { wrap_total: 0, wrap_match: 0, all_total: 0, all_match: 0, mism_examples: Vec::new() };
    run_model(|flats| group_widths(flats), &mut t, &corpus);
    eprintln!("=== group_widths (current smallest-first) ===");
    eprintln!(
        "wrapping prem/concl cells: {}/{} = {:.3}%",
        t.wrap_match,
        t.wrap_total,
        100.0 * t.wrap_match as f64 / t.wrap_total as f64
    );
    eprintln!(
        "all prem/concl cells:      {}/{} = {:.3}%",
        t.all_match,
        t.all_total,
        100.0 * t.all_match as f64 / t.all_total as f64
    );
    let show = std::env::var("SHOW_MISM").is_ok();
    if show {
        for (flat, want, got) in t.mism_examples.iter().take(30) {
            eprintln!("--- flat: {flat}");
            eprintln!("    want: {want}");
            eprintln!("    got : {got}");
        }
    }
}

